function parseLastJson(stdout) {
  const lines = String(stdout || '').split(/\r?\n/).map(line => line.trim()).filter(Boolean).reverse();
  for (const line of lines) {
    if (!(line.startsWith('{') && line.endsWith('}'))) continue;
    try {
      return JSON.parse(line);
    } catch (error) {
      continue;
    }
  }
